import { Component, Input, OnInit, TemplateRef } from '@angular/core';
import { NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { ToastrService } from 'ngx-toastr';
import { Order } from 'src/app/common/Order';
import { OrderDetail } from 'src/app/common/OrderDetail';
import { OrderService } from 'src/app/services/order.service';
import { ReturnService } from 'src/app/services/return.service';
import { UploadService } from 'src/app/services/upload.service';
import Swal from 'sweetalert2';

@Component({
  selector: 'app-order-detail',
  templateUrl: './order-detail.component.html',
  styleUrls: ['./order-detail.component.css']
})
export class OrderDetailComponent implements OnInit {
  orderDetails!: OrderDetail[];
  order!: Order;

  @Input() id!: number;

  constructor(
    private modalService: NgbModal,
    private orderService: OrderService,
    private returnService: ReturnService, // Đã thêm
    private uploadService: UploadService, // Đã thêm
    private toastr: ToastrService
  ) { }

  ngOnInit(): void {
    this.getOrder();
    this.getItems();
  }

  getOrder() {
    this.orderService.getById(this.id).subscribe(data => {
      this.order = data as Order;
    }, error => this.toastr.error('Lỗi server', 'Hệ thống'));
  }

  getItems() {
    this.orderService.getByOrder(this.id).subscribe(data => {
      this.orderDetails = data as OrderDetail[];
    });
  }

  open(content: TemplateRef<any>) {
    this.modalService.open(content, { centered: true, size: 'lg' });
  }

  async requestCancelOrReturn() {
    const isReturn = this.order.status === 2; // Nếu đã xong thì là Trả hàng, còn lại là Hủy

    const { value: formValues } = await Swal.fire({
      title: isReturn ? 'Yêu cầu Trả hàng/Hoàn tiền' : 'Yêu cầu Hủy đơn hàng',
      html: `
        <div class="swal-custom-form">
          <label>Lý do:</label>
          <select id="swal-reason" class="swal2-input" style="width: 80%; font-size: 15px">
            <option value="Đổi ý, không muốn mua nữa">Đổi ý, không muốn mua nữa</option>
            <option value="Sản phẩm không giống mô tả">Sản phẩm không giống mô tả</option>
            <option value="Hàng bị hư hỏng/vỡ">Hàng bị hư hỏng/vỡ</option>
            <option value="Giao sai hàng">Giao sai hàng</option>
            <option value="Khác">Khác...</option>
          </select>
          <label>Mô tả chi tiết:</label>
          <textarea id="swal-desc" class="swal2-textarea" placeholder="Nhập chi tiết lý do..."></textarea>
          ${isReturn ? `
            <label>Ảnh bằng chứng (Hàng lỗi/hỏng):</label>
            <input type="file" id="swal-file" class="swal2-file" accept="image/*">
          ` : ''}
        </div>
      `,
      focusConfirm: false,
      showCancelButton: true,
      confirmButtonText: 'Gửi yêu cầu',
      cancelButtonText: 'Đóng',
      preConfirm: () => {
        const reason = (document.getElementById('swal-reason') as HTMLSelectElement).value;
        const description = (document.getElementById('swal-desc') as HTMLTextAreaElement).value;
        const fileInput = document.getElementById('swal-file') as HTMLInputElement;

        if (!description) {
          Swal.showValidationMessage('Vui lòng nhập mô tả chi tiết');
          return false;
        }

        return { reason, description, file: fileInput ? fileInput.files?.[0] : null };
      }
    });

    if (formValues) {
      Swal.showLoading();
      let imageUrl = '';

      // Xử lý upload ảnh nếu có file (Trường hợp Trả hàng)
      if (formValues.file) {
        try {
          const uploadRes = await this.uploadService.uploadCustomer(formValues.file).toPromise();
          imageUrl = uploadRes.secure_url;
        } catch (e) {
          this.toastr.error('Lỗi upload ảnh bằng chứng');
          return;
        }
      }

      const returnRequest = {
        order: { ordersId: this.order.ordersId },
        reason: formValues.reason,
        description: formValues.description,
        evidenceImage: imageUrl,
        status: 0
      };

      this.returnService.save(returnRequest).subscribe(() => {
        this.toastr.success('Yêu cầu của bạn đã được gửi tới quản trị viên', 'Hệ thống');
        this.getOrder();
        this.modalService.dismissAll();
        Swal.close();
      });
    }
  }

  finish() { this.ngOnInit(); }
}
